const lines = input.trim().split('\n').filter(Boolean);
const jsonLogs = lines.filter(l => { try { const o = JSON.parse(l.trim()); return typeof o === 'object'; } catch { return false; } });
const nginxLogs = lines.filter(l => /^[\d.]+\s+-.+\[.+\]\s+"/.test(l)).length;
const ratio = (jsonLogs.length + nginxLogs) / Math.max(1, lines.length);
return ratio > 0.3 ? 0.93 : ratio > 0.1 ? 0.6 : 0;

plugin.executeCode:
const LEVEL_LABELS = { 'error': '  ERROR', 'err': '  ERROR', 'fatal': '  FATAL', 'warn': '   WARN', 'warning': '   WARN', 'info': '   INFO', 'debug': '  DEBUG', 'trace': '  TRACE' };
const lines = input.trim().split('\n');
const out = [];
for (const raw of lines) {
  const line = raw.trim();
  if (!line) { out.push(''); continue; }
  // Try JSON log
  try {
    const obj = JSON.parse(line);
    if (typeof obj === 'object' && obj !== null) {
      const level = (obj.level || obj.severity || obj.lvl || obj.l || '').toLowerCase();
      const msg = obj.message || obj.msg || obj.m || '';
      const time = obj.time || obj.timestamp || obj.ts || obj.datetime || '';
      const label = LEVEL_LABELS[level] || '   LOG ';
      const prefix = time ? `[${time}] ${label}` : label;
      // Extract remaining keys
      const skip = new Set(['level','severity','lvl','l','message','msg','m','time','timestamp','ts','datetime']);
      const extra = Object.entries(obj).filter(([k]) => !skip.has(k)).map(([k,v]) => `${k}=${JSON.stringify(v)}`).join(' ');
      out.push(`${prefix}  ${msg}${extra ? '  ' + extra : ''}`);
      continue;
    }
  } catch {}
  // Try nginx combined log: IP - - [date] "method path proto" status size
  const nginx = line.match(/^([\d.a-fA-F:]+)\s+\S+\s+\S+\s+\[([^\]]+)\]\s+"(\S+)\s+(\S+)\s+(\S+)"\s+(\d+)\s+(\d+)/);
  if (nginx) {
    const [, ip, date, method, path, proto, status, size] = nginx;
    const s = parseInt(status);
    const lvl = s >= 500 ? '  ERROR' : s >= 400 ? '   WARN' : '   INFO';
    out.push(`[${date}] ${lvl}  ${method} ${path} → ${status}  (${size}B)  ${ip}`);
    continue;
  }
  out.push(line);
}
return { output: out.join('\n'), outputLanguage: 'text' };
